function solve(nums) {
    const indices1 = [];
    const indices2 = [];

    // 1. Find indices of 1s and 2s
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 1) {
            indices1.push(i);
        } else if (nums[i] === 2) {
            indices2.push(i);
        }
    }

    // 2. Check for existence
    if (indices1.length === 0 || indices2.length === 0) {
        return -1;
    }

    // 3. Calculate minimum difference using two pointers (O(N))
    let minDiff = Number.POSITIVE_INFINITY;
    let p1 = 0;
    let p2 = 0;

    while (p1 < indices1.length && p2 < indices2.length) {
        const i = indices1[p1];
        const j = indices2[p2];

        const diff = Math.abs(i - j);
        minDiff = Math.min(minDiff, diff);

        // Move the pointer associated with the smaller index to try and reduce the gap
        if (i < j) {
            p1++;
        } else {
            p2++;
        }
    }

    return minDiff;
}

